params.query:
-- Drop existing policies if any
DROP POLICY IF EXISTS "Allow anonymous insert on tracking_sessions" ON tracking_sessions;
DROP POLICY IF EXISTS "Allow anonymous read on tracking_sessions" ON tracking_sessions;
DROP POLICY IF EXISTS "Allow anonymous update on tracking_sessions" ON tracking_sessions;
DROP POLICY IF EXISTS "Allow public read on tracking_sessions" ON tracking_sessions;
DROP POLICY IF EXISTS "Allow public insert on tracking_sessions" ON tracking_sessions;
DROP POLICY IF EXISTS "Allow public update on tracking_sessions" ON tracking_sessions;

-- Enable RLS on tracking_sessions (if not already enabled)
ALTER TABLE tracking_sessions ENABLE ROW LEVEL SECURITY;

-- Allow anyone to insert tracking sessions (for anonymous tracking)
CREATE POLICY "Allow public insert on tracking_sessions"
ON tracking_sessions
FOR INSERT
TO anon, authenticated
WITH CHECK (true);

-- Allow anyone to read tracking sessions by tracking_code (for public tracking links)
CREATE POLICY "Allow public read on tracking_sessions"
ON tracking_sessions
FOR SELECT
TO anon, authenticated
USING (true);

-- Allow anyone to update tracking sessions (for status updates)
CREATE POLICY "Allow public update on tracking_sessions"
ON tracking_sessions
FOR UPDATE
TO anon, authenticated
USING (true)
WITH CHECK (true);

-- Drop existing policies on locations if any
DROP POLICY IF EXISTS "Allow anonymous insert on locations" ON locations;
DROP POLICY IF EXISTS "Allow anonymous read on locations" ON locations;
DROP POLICY IF EXISTS "Allow public insert on locations" ON locations;
DROP POLICY IF EXISTS "Allow public read on locations" ON locations;

-- Enable RLS on locations (if not already enabled)
ALTER TABLE locations ENABLE ROW LEVEL SECURITY;

-- Allow anyone to insert location updates
CREATE POLICY "Allow public insert on locations"
ON locations
FOR INSERT
TO anon, authenticated
WITH CHECK (true);

-- Allow anyone to read location updates
CREATE POLICY "Allow public read on locations"
ON locations
FOR SELECT
TO anon, authenticated
USING (true);
